+    local procedure NormalizeContractEntryNoFilter(var FilterText: Text)
+    var
+        RemainingFilter: Text;
+        Token: Text;
+    begin
+        if FilterText = '' then
+            exit;
+        RemainingFilter := FilterText;
+        FilterText := '';
+        while RemainingFilter <> '' do begin
+            Token := ExtractFilterToken(RemainingFilter);
+            Token := NormalizeRangeToken(Token);
+            if FilterText <> '' then
+                FilterText += '|';
+            FilterText += Token;
+        end;
+    end;
+
+    local procedure ExtractFilterToken(var FilterText: Text): Text
+    var
+        Position: Integer;
+        Token: Text;
+    begin
+        if FilterText = '' then
+            exit('');
+
+        Position := STRPOS(FilterText, '|');
+        if Position = 0 then begin
+            Token := FilterText;
+            FilterText := '';
+            exit(Token);
+        end;
+
+        Token := COPYSTR(FilterText, 1, Position - 1);
+        FilterText := COPYSTR(FilterText, Position + 1);
+        exit(Token);
+    end;
+
+    local procedure NormalizeRangeToken(Token: Text): Text
+    var
+        RangePosition: Integer;
+        LowerText: Text;
+        UpperText: Text;
+        LowerValue: Decimal;
+        UpperValue: Decimal;
+    begin
+        RangePosition := STRPOS(Token, '..');
+        if RangePosition = 0 then
+            exit(Token);
+
+        LowerText := COPYSTR(Token, 1, RangePosition - 1);
+        UpperText := COPYSTR(Token, RangePosition + 2);
+        if Evaluate(LowerValue, RemoveWrappingQuotes(LowerText)) and Evaluate(UpperValue, RemoveWrappingQuotes(UpperText)) and (UpperValue < LowerValue) then
+            exit(UpperText + '..' + LowerText);
+
+        exit(Token);
+    end;
+
+    local procedure RemoveWrappingQuotes(Value: Text): Text
+    var
+        ValueLength: Integer;
+    begin
+        ValueLength := STRLEN(Value);
+        if (ValueLength >= 2) and (CopyStr(Value, 1, 1) = '''') and (CopyStr(Value, ValueLength, 1) = '''') then
+            exit(COPYSTR(Value, 2, ValueLength - 2));
+        exit(Value);
+    end;
+
