+    local procedure EnsureVATSettlementJournal(var GenJnlLine: Record "Gen. Journal Line")
+    begin
+        if not GLSetup."Journal Templ. Name Mandatory" then
+            exit;
+        if GenJnlLine."Journal Template Name" = '' then
+            GenJnlLine.Validate("Journal Template Name", GetVATSettlementTemplateName());
+        if GenJnlLine."Journal Batch Name" = '' then
+            GenJnlLine.Validate("Journal Batch Name", GetVATSettlementBatchName());
+    end;
+
+    local procedure GetVATSettlementTemplateName(): Code[10]
+    var
+        GenJnlTemplate: Record "Gen. Journal Template";
+    begin
+        if VATSettlementTemplateName <> '' then
+            exit(VATSettlementTemplateName);
+        GenJnlTemplate.Reset();
+        GenJnlTemplate.SetRange("Page ID", PAGE::"General Journal");
+        GenJnlTemplate.SetRange(Recurring, false);
+        GenJnlTemplate.SetRange(Type, GenJnlTemplate.Type::General);
+        if not GenJnlTemplate.FindFirst() then
+            Error(NoVATSettlementTemplateErr);
+        VATSettlementTemplateName := GenJnlTemplate.Name;
+        exit(VATSettlementTemplateName);
+    end;
+
+    local procedure GetVATSettlementBatchName(): Code[10]
+    var
+        GenJnlBatch: Record "Gen. Journal Batch";
+        TemplateName: Code[10];
+        Candidate: Code[10];
+        Counter: Integer;
+    begin
+        if VATSettlementBatchName <> '' then
+            exit(VATSettlementBatchName);
+        TemplateName := GetVATSettlementTemplateName();
+        Counter := 1;
+        repeat
+            Candidate := StrSubstNo('VATSET%1', Counter);
+            GenJnlBatch.Reset();
+            if not GenJnlBatch.Get(TemplateName, Candidate) then
+                break;
+            Counter += 1;
+        until Counter > 9999;
+        if Counter > 9999 then
+            Error(CannotCreateVATSettlementBatchErr);
+        GenJnlBatch.Init();
+        GenJnlBatch.Validate("Journal Template Name", TemplateName);
+        GenJnlBatch.Validate(Name, Candidate);
+        GenJnlBatch.Description := CalcandPostVATSettlementCaptionLbl;
+        GenJnlBatch.SetupNewBatch();
+        GenJnlBatch.Insert(true);
+        VATSettlementBatchName := Candidate;
+        exit(VATSettlementBatchName);
+    end;
